-- Migration: company row-level-security fence for manufacturing.workstations
-- Generated by metaphor-schema (ADR-0008). company_id is scoped per request
-- via `set_config('app.company_id', <uuid>, true)`; an unset var sees zero rows.

ALTER TABLE manufacturing.workstations ENABLE ROW LEVEL SECURITY;
ALTER TABLE manufacturing.workstations FORCE  ROW LEVEL SECURITY;
DROP POLICY IF EXISTS workstations_company_isolation ON manufacturing.workstations;
CREATE POLICY workstations_company_isolation ON manufacturing.workstations
    FOR ALL
    USING      (company_id = NULLIF(current_setting('app.company_id', true), '')::uuid)
    WITH CHECK (company_id = NULLIF(current_setting('app.company_id', true), '')::uuid);

